        return {
            "status": "ok",
            "has_managed_section": False,
            "markers_valid": False,
            "error_detail": "Found <!-- SKF:BEGIN but no matching <!-- SKF:END -->",
        }
    elif not has_begin and has_end:
        return {
            "status": "ok",
            "has_managed_section": False,
            "markers_valid": False,
            "error_detail": "Found <!-- SKF:END --> but no matching <!-- SKF:BEGIN",
        }
